    val px = Array.tabulate(n)(i => arr(1 + 2 * i))
    val py = Array.tabulate(n)(i => arr(1 + 2 * i + 1))

    def cross(o: Int, a: Int, b: Int): Int =
      (px(a) - px(o)) * (py(b) - py(o)) - (py(a) - py(o)) * (px(b) - px(o))

